    cpcBidFloorMicros: external_exports.number().optional().describe("Minimum CPC bid floor in micros. Supported for TARGET_CPA, TARGET_ROAS, MAXIMIZE_CONVERSIONS, MAXIMIZE_CONVERSION_VALUE."),
    targetImpressionShareLocation: external_exports.enum(["ANYWHERE_ON_PAGE", "TOP_OF_PAGE", "ABSOLUTE_TOP_OF_PAGE"]).optional().describe("Required for TARGET_IMPRESSION_SHARE. Where on the search results page to target."),
    targetImpressionShareFraction: external_exports.number().min(0).max(1).optional().describe("Required for TARGET_IMPRESSION_SHARE. Target fraction of auctions to show your ad (0.0\u20131.0, e.g. 0.9 = 90%)."),
    targetImpressionShareCpcCeilingMicros: external_exports.number().optional().describe("Optional max CPC bid ceiling in micros for TARGET_IMPRESSION_SHARE."),
