var createGoogleAdsCustomerMatchTool = createTool2({
  id: "create-google-ads-customer-match",
  mcp: { annotations: { idempotentHint: false, destructiveHint: false, openWorldHint: true } },
  description: `Create a Customer Match audience by uploading hashed email, phone, or address data. This creates a CRM-based user list and uploads member data in one call.

The backend handles SHA-256 hashing automatically \u2014 you can send raw (unhashed) emails and phone numbers. Set preHashed=true only if data is already hashed.

IMPORTANT: Consent is required by Google policy. You must include consent: { adUserData: "GRANTED", adPersonalization: "GRANTED" }.

Upload key types:
- CONTACT_INFO: For email, phone, name, address data (most common)
- CRM_ID: For third-party CRM user IDs
- MOBILE_ADVERTISING_ID: For mobile advertising IDs (IDFA/GAID)

Each member object can include: email, phone, firstName, lastName, countryCode, zipCode, crmId, mobileId.
Maximum 5000 members per call. The backend batches uploads internally.`,
  inputSchema: external_exports.object({
    customerId: external_exports.string().describe("The Google Ads customer ID (digits only, no dashes)"),
    listName: external_exports.string().describe("Name for the new Customer Match user list"),
    description: external_exports.string().optional().describe("Optional description for the user list"),
    membershipLifeSpan: external_exports.number().optional().default(30).describe("How long (in days) a user stays in the list. Default: 30. Max: 540. Use 10000 for no expiry."),
    uploadKeyType: external_exports.enum(["CONTACT_INFO", "CRM_ID", "MOBILE_ADVERTISING_ID"]).optional().default("CONTACT_INFO").describe("The type of user identifiers being uploaded. Default: CONTACT_INFO."),
    members: external_exports.array(external_exports.object({
      email: external_exports.string().optional().describe("Email address (will be hashed by backend)"),
      phone: external_exports.string().optional().describe("Phone number with country code, e.g. +1234567890 (will be hashed)"),
      firstName: external_exports.string().optional().describe("First name (will be hashed)"),
      lastName: external_exports.string().optional().describe("Last name (will be hashed)"),
      countryCode: external_exports.string().optional().describe("Two-letter country code, e.g. US, GB"),
      zipCode: external_exports.string().optional().describe("Postal/zip code"),
      crmId: external_exports.string().optional().describe("Third-party CRM user ID (for CRM_ID upload key type)"),
      mobileId: external_exports.string().optional().describe("Mobile advertising ID \u2014 IDFA or GAID (for MOBILE_ADVERTISING_ID key type)")
    })).min(1).max(5e3).describe("Array of member data to upload. At least one identifier per member. Max 5000."),
    consent: external_exports.object({
      adUserData: external_exports.enum(["GRANTED", "DENIED"]).describe("User consent for ad user data. Must be GRANTED."),
      adPersonalization: external_exports.enum(["GRANTED", "DENIED"]).describe("User consent for ad personalization. Must be GRANTED.")
    }).describe("Required consent signals. Both must be GRANTED for the upload to succeed."),
    preHashed: external_exports.boolean().optional().default(false).describe("Set to true if emails/phones/names are already SHA-256 hashed. Default: false (backend hashes automatically)."),
    loginCustomerId: external_exports.string().optional().describe("Manager account (MCC) customer ID. Required when accessing sub-accounts under a manager account.")
  }),
  outputSchema: external_exports.object({
    success: external_exports.boolean(),
    userListId: external_exports.string().optional().describe("The ID of the created user list"),
    userListResourceName: external_exports.string().optional().describe("Full resource name of the user list"),
    jobResourceName: external_exports.string().optional().describe("The offline user data job resource name (for tracking upload status)"),
    membersUploaded: external_exports.number().optional().describe("Number of members submitted for upload"),
    message: external_exports.string().optional()
  }),
  execute: async ({ customerId, listName, description, membershipLifeSpan, uploadKeyType, members, consent, preHashed, loginCustomerId }) => {
    try {
      const result = await callGoogleAdsApiWrite("/customer-match", "POST", {
        customerId,
        listName,
        description,
        membershipLifeSpan,
        uploadKeyType,
        members,
        consent,
        preHashed,
        loginCustomerId
      });
      return {
        success: true,
        userListId: result.userListId,
        userListResourceName: result.userListResourceName,
        jobResourceName: result.jobResourceName,
        membersUploaded: result.membersUploaded,
        message: `Customer Match list "${listName}" created with ${result.membersUploaded ?? members.length} members. Job: ${result.jobResourceName ?? "submitted"}.`
      };
    } catch (error3) {
      return {
        success: false,
        message: `Failed to create Customer Match audience: ${error3 instanceof Error ? error3.message : "Unknown error"}`
      };
    }
  }
});

