var getGraphAdPreviewsTool = createTool2({
  id: "get-graph-ad-previews",
  mcp: { annotations: { readOnlyHint: true } },
  description: "Generate live HTML iframe previews for a Facebook ad creative across different placements (Feed, Story, Instagram, etc.). Returns the previewBody HTML for each format \u2014 embed it in a browser to render the preview. Available ad formats: DESKTOP_FEED_STANDARD, MOBILE_FEED_STANDARD, FACEBOOK_STORY_MOBILE, INSTAGRAM_STANDARD, INSTAGRAM_STORY, RIGHT_COLUMN_STANDARD, MARKETPLACE_MOBILE, SUGGESTED_VIDEO_MOBILE, INSTREAM_VIDEO_MOBILE, SEARCH_MOBILE. If adFormats is omitted, all five main placements are returned by default.",
  inputSchema: external_exports.object({
    adAccountId: external_exports.string().describe("The ad account ID (format: act_XXXXXXXXX)"),
    creativeId: external_exports.string().describe("The ad creative ID to preview"),
    adFormats: external_exports.array(
      external_exports.enum([
        "DESKTOP_FEED_STANDARD",
        "MOBILE_FEED_STANDARD",
        "FACEBOOK_STORY_MOBILE",
        "INSTAGRAM_STANDARD",
        "INSTAGRAM_STORY",
        "RIGHT_COLUMN_STANDARD",
        "MARKETPLACE_MOBILE",
        "SUGGESTED_VIDEO_MOBILE",
        "INSTREAM_VIDEO_MOBILE",
        "SEARCH_MOBILE"
      ])
    ).optional().describe("Placements to preview. Defaults to the 5 main placements if omitted.")
  }),
  outputSchema: external_exports.object({
    success: external_exports.boolean(),
    creativeId: external_exports.string().optional(),
    previews: external_exports.array(
      external_exports.object({
        adFormat: external_exports.string(),
        previewBody: external_exports.string().nullable(),
        success: external_exports.boolean(),
        error: external_exports.string().optional()
      })
    ),
    message: external_exports.string().optional()
  }),
  execute: async ({ adAccountId, creativeId, adFormats }) => {
    try {
      const result = await callApi(`/creatives/${creativeId}/previews`, {
        adAccountId,
        adFormats: adFormats?.join(",")
      });
      const successful = result.data.previews.filter((p) => p.success).length;
      return {
        success: true,
        creativeId: result.data.creativeId,
        previews: result.data.previews,
        message: result.message
      };
    } catch (error3) {
      return {
        success: false,
        previews: [],
        message: `Failed to generate previews: ${error3 instanceof Error ? error3.message : "Unknown error"}`
      };
    }
  }
});
