var createMetaCustomAudienceTool = createTool2({
  id: "create-meta-custom-audience",
  mcp: { annotations: { readOnlyHint: false } },
  description: "Create a custom audience for a Meta ad account. Supports customer list (CUSTOM), website traffic (WEBSITE), and engagement (ENGAGEMENT) subtypes.",
  inputSchema: external_exports.object({
    adAccountId: external_exports.string().describe("The Meta ad account ID (format: act_XXXXXXXXX)"),
    name: external_exports.string().describe("Audience name"),
    subtype: external_exports.enum(["CUSTOM", "WEBSITE", "ENGAGEMENT", "APP"]).describe("Audience type: CUSTOM (customer list), WEBSITE (pixel-based), ENGAGEMENT, APP"),
    description: external_exports.string().optional().describe("Optional audience description"),
    customerFileSource: external_exports.enum(["USER_PROVIDED_ONLY", "PARTNER_PROVIDED_ONLY", "BOTH_USER_AND_PARTNER_PROVIDED"]).optional().describe("Source of customer file data (for CUSTOM subtype)"),
    pixelId: external_exports.string().optional().describe("Meta Pixel ID \u2014 required for WEBSITE subtype. A PageView rule is auto-built using this pixel."),
    pageId: external_exports.string().optional().describe("Facebook Page ID \u2014 for ENGAGEMENT subtype (page engagement). Builds a page_engaged rule automatically."),
    videoId: external_exports.string().optional().describe("Video ID \u2014 for ENGAGEMENT subtype (video viewers). Builds a video.percentage rule automatically. Get video IDs from get-meta-ad-videos."),
    videoPercentage: external_exports.number().int().min(1).max(100).optional().describe("Minimum video watched percentage for video viewer audiences (default 50). e.g. 25, 50, 75, 95, 100."),
    retentionDays: external_exports.number().int().min(1).max(180).optional().describe("Lookback window in days. WEBSITE: 1\u2013180 (default 30). ENGAGEMENT: 1\u2013180 (default 60)."),
    rule: external_exports.record(external_exports.any()).optional().describe("Advanced: custom rule object for WEBSITE subtype only. If omitted, a PageView rule is auto-built from pixelId."),
    prefill: external_exports.boolean().optional().describe("Whether to prefill with historical data (WEBSITE subtype)")
  }),
  outputSchema: external_exports.object({
    success: external_exports.boolean(),
    audienceId: external_exports.string().optional(),
    message: external_exports.string().optional()
  }),
  execute: async ({ adAccountId, name, subtype, description, customerFileSource, pixelId, pageId, videoId, videoPercentage, retentionDays, rule, prefill }) => {
    try {
      const result = await callApiWrite("/audiences", "POST", { adAccountId, name, subtype, description, customerFileSource, pixelId, pageId, videoId, videoPercentage, retentionDays, rule, prefill });
      return { success: true, audienceId: result.data.audienceId, message: result.message };
    } catch (error3) {
      return { success: false, message: `Failed to create custom audience: ${error3 instanceof Error ? error3.message : "Unknown error"}` };
    }
  }
});
