    placementType: external_exports.enum(["PLACEMENT_TYPE_AUTOMATIC", "PLACEMENT_TYPE_NORMAL"]).optional().describe("Placement type. Use PLACEMENT_TYPE_NORMAL for REACH and VIDEO_VIEWS campaigns (required by TikTok for those objectives). Default: PLACEMENT_TYPE_AUTOMATIC."),
    placements: external_exports.array(external_exports.enum(["PLACEMENT_TIKTOK", "PLACEMENT_PANGLE", "PLACEMENT_TOPBUZZ"])).optional().describe('Explicit placements when placementType is PLACEMENT_TYPE_NORMAL. Defaults to ["PLACEMENT_TIKTOK"] if not provided. Required for REACH and VIDEO_VIEWS campaigns.'),
