function toMcpTool(tool) {
  const schema = tool.inputSchema ?? external_exports.object({});
  const { $schema, ...inputSchema } = zodToJsonSchema(schema, {
    target: "jsonSchema7",
    $refStrategy: "none"
  });
  return { name: tool.id, description: tool.description, inputSchema };
}
