function findExecutionPlan(query) {
  const q = query.toLowerCase();
  const tokens = q.split(/\s+/);
  let bestMatch;
  for (const [key, plan] of Object.entries(executionPlans)) {
    let score = 0;
    for (const trigger of plan.trigger) {
      if (q.includes(trigger)) score += trigger.split(/\s+/).length + 1;
      for (const token of tokens) {
        if (trigger.includes(token)) score += 0.5;
      }
    }
    if (score > 0 && (!bestMatch || score > bestMatch.score)) {
      bestMatch = { key, score };
    }
  }
  return bestMatch ? executionPlans[bestMatch.key].steps : void 0;
}
function searchTools(query, options) {
  const limit = options?.limit ?? 10;
  const queryTokens = query.toLowerCase().split(/[^a-z0-9]+/).filter((t) => t.length > 1);
  const scored = [];
  for (const entry of registry2.values()) {
    if (options?.platform && entry.platform !== options.platform) continue;
    if (options?.category && entry.category !== options.category) continue;
    if (options?.operation && entry.operation !== options.operation) continue;
    let score = 0;
    for (const token of queryTokens) {
      if (entry.keywords.includes(token)) score += 2;
      else if (entry.keywords.some((k) => k.includes(token) || token.includes(k))) score += 1;
    }
    if (queryTokens.some((t) => t === entry.platform || entry.keywords.includes(t))) score += 1;
    if (score > 0) scored.push({ ...entry, score });
  }
  scored.sort((a, b) => b.score - a.score);
  const top = scored.slice(0, limit);
  return {
    tools: top.map(({ score, keywords, execute, ...rest }) => ({ ...rest, score })),
    executionPlan: findExecutionPlan(query),
    total: top.length
  };
}
async function executeToolById(id, args) {
  const entry = registry2.get(id);
  if (!entry) throw new Error(`Unknown tool: ${id}`);
  return entry.execute(args);
}
function getToolSchemas(ids) {
  const schemas = {};
  const notFound = [];
  for (const id of ids) {
    const entry = registry2.get(id);
    if (entry) {
      schemas[id] = {
        id: entry.id,
        platform: entry.platform,
        category: entry.category,
        operation: entry.operation,
        description: entry.description,
        inputSchema: entry.inputSchema
      };
    } else {
      notFound.push(id);
    }
  }
  return { schemas, notFound };
}
function getRegistrySize() {
  return registry2.size;
}
function registerSkillTools(skills) {
  let count = 0;
  for (const skill of skills) {
    const toolId = `skill_${skill.name}`;
    if (registry2.has(toolId)) continue;
    const entry = {
      id: toolId,
      platform: "skills",
      category: "other",
      operation: "read",
      description: skill.description,
      keywords: extractKeywords(toolId, skill.description, "skills", "other"),
      inputSchema: { type: "object", properties: {}, required: [] },
      execute: async () => skill.execute()
    };
    registry2.set(toolId, entry);
    count++;
  }
  if (count > 0) {
    console.error(`[ToolRegistry] Registered ${count} skill tool(s)`);
  }
  return count;
}

